/*
 * Sequential Circuits: JK Flip-Flop Implementation
 * Demonstrates JK flip-flop behavior and synchronous state machine
 */

#include <stdio.h>
#include <stdbool.h>

// JK Flip-Flop structure
typedef struct {
 int q; // Present state output
 int q_bar; // Complement output
 int j; // J input
 int k; // K input
} JKFlipFlop;

// Initialize JK flip-flop
void jk_ff_init(JKFlipFlop *ff) {
 ff->q = 0;
 ff->q_bar = 1;
 ff->j = 0;
 ff->k = 0;
}

// Set J and K inputs (combinational - immediate)
void jk_ff_set_inputs(JKFlipFlop *ff, int j, int k) {
 ff->j = j;
 ff->k = k;
}

// Clock tick - updates state on rising edge
// Returns true if state changed
bool jk_ff_clock(JKFlipFlop *ff, bool rising_edge) {
 if (!rising_edge) return false;

 int j = ff->j;
 int k = ff->k;

 // JK Flip-Flop truth table:
 // J=0, K=0: No change (hold)
 // J=0, K=1: Reset (Q=0)
 // J=1, K=0: Set (Q=1)
 // J=1, K=1: Toggle (Q = !Q)

 if (j == 0 && k == 0) {
 // Hold current state
 } else if (j == 0 && k == 1) {
 ff->q = 0; // Reset
 } else if (j == 1 && k == 0) {
 ff->q = 1; // Set
 } else { // j==1 && k==1
 ff->q = !(ff->q); // Toggle
 }

 ff->q_bar = 1 - ff->q;
 return true;
}

// 2-Bit Counter using JK flip-flops
typedef struct {
 JKFlipFlop ff0; // LSB
 JKFlipFlop ff1; // MSB
} TwoBitCounter;

// Initialize counter
void counter_init(TwoBitCounter *counter) {
 jk_ff_init(&counter->ff0);
 jk_ff_init(&counter->ff1);
}

// Compute JK inputs for counter (combinational logic)
void counter_compute_inputs(TwoBitCounter *counter) {
 int q0 = counter->ff0.q; // Current LSB
 int q1 = counter->ff1.q; // Current MSB

 // For JK flip-flop:
 // T (toggle) = J = K = 1 when toggle needed
 // J0 = K0 = 1 (toggle FF0 every clock)
 jk_ff_set_inputs(&counter->ff0, 1, 1);

 // J1 = K1 = Q0 (toggle FF1 when Q0=1)
 jk_ff_set_inputs(&counter->ff1, q0, q0);
}

// Clock tick for counter
void counter_clock(TwoBitCounter *counter) {
 // Step 1: Compute next state inputs (combinational)
 counter_compute_inputs(counter);

 // Step 2: Update flip-flops on rising edge (memory)
 jk_ff_clock(&counter->ff0, true);
 jk_ff_clock(&counter->ff1, true);
}

// Get counter value
int counter_get_value(TwoBitCounter *counter) {
 return (counter->ff1.q << 1) | counter->ff0.q;
}

int main() {
 printf("========================================\n");
 printf("JK Flip-Flop 2-Bit Counter Simulation\n");
 printf("========================================\n\n");

 TwoBitCounter counter;
 counter_init(&counter);

 printf("Clock | Q1 Q0 | Binary | Decimal\n");
 printf("------|-------|--------|--------\n");

 for (int i = 0; i < 8; i++) {
 int value = counter_get_value(&counter);
 printf(" %d | %d %d | %d | %d\n", 
 i+1, counter.ff1.q, counter.ff0.q, value, value);

 // Show JK inputs before clock
 printf(" | J1=%d,K1=%d | J0=%d,K0=%d\n",
 counter.ff1.j, counter.ff1.k, counter.ff0.j, counter.ff0.k);

 counter_clock(&counter);
 }

 printf("\nJK Flip-Flop Truth Table:\n");
 printf("J K | Action\n");
 printf("----|--------\n");
 printf("0 0 | Hold (no change)\n");
 printf("0 1 | Reset (Q=0)\n");
 printf("1 0 | Set (Q=1)\n");
 printf("1 1 | Toggle (Q=!Q)\n");

 return 0;
}

/*
 * Sequential Circuits: Mealy State Machine
 * Detects the sequence '10' in input stream
 * Output depends on present state AND current input (Mealy model)
 */

#include <stdio.h>
#include <stdbool.h>

// State definitions for sequence detector
typedef enum {
 STATE_A, // Initial state - no '1' received yet
 STATE_B // '1' received, waiting for '0'
} State;

// Mealy State Machine structure
typedef struct {
 State present_state;
 int output; // 1 if sequence '10' detected
} MealyMachine;

// Initialize state machine
void machine_init(MealyMachine *machine) {
 machine->present_state = STATE_A;
 machine->output = 0;
}

// Mealy state transition and output function
// Output = f(Present State, Input) - characteristic of Mealy machine
void machine_process_input(MealyMachine *machine, int input_bit) {
 State current = machine->present_state;
 int output = 0;
 State next_state;

 // State transition logic
 switch (current) {
 case STATE_A: // No '1' yet
 if (input_bit == 1) {
 next_state = STATE_B; // Got '1', now wait for '0'
 } else {
 next_state = STATE_A; // Still no '1'
 }
 break;

 case STATE_B: // Previously got '1'
 if (input_bit == 0) {
 // Sequence '10' detected!
 output = 1;
 next_state = STATE_A; // Reset to look for new sequence
 } else {
 // Still have '1', stay in state B
 next_state = STATE_B;
 }
 break;
 }

 // Update state (synchronous - happens on clock edge)
 machine->present_state = next_state;
 machine->output = output;
}

// Display state machine status
void display_status(MealyMachine *machine, int clock, int input) {
 const char *state_name = (machine->present_state == STATE_A) ? "A" : "B";
 printf("Clock %d: Input=%d | State=%s | Output=%d\n",
 clock, input, state_name, machine->output);
}

int main() {
 printf("============================================\n");
 printf("Mealy State Machine: Sequence '10' Detector\n");
 printf("============================================\n\n");

 printf("Mealy Machine: Output = f(Present State, Input)\n");
 printf("Output can change during clock cycle based on input\n\n");

 MealyMachine machine;
 machine_init(&machine);

 // Test sequence: 1 0 1 1 0 0 1 0 1 0
 int test_input[] = {1, 0, 1, 1, 0, 0, 1, 0, 1, 0};
 int input_count = sizeof(test_input) / sizeof(test_input[0]);

 printf("Input Sequence Analysis:\n");
 printf("------------------------\n");

 for (int i = 0; i < input_count; i++) {
 machine_process_input(&machine, test_input[i]);
 display_status(&machine, i + 1, test_input[i]);
 }

 printf("\n--- State Transition Diagram ---\n");
 printf(" 1 1\n");
 printf(" [A]------>[B]-------->[B]\n");
 printf(" ^ | /| /|\n");
 printf(" | | 0 | | 0 | |\n");
 printf(" | v | v | v\n");
 printf(" +----[A]--+----[A]---+--\n");
 printf(" Output:1 only when entering A from B with input=0\n");

 printf("\nKey Differences (Mealy vs Moore):\n");
 printf("- Mealy: Output depends on BOTH state AND input\n");
 printf("- Moore: Output depends only on present state\n");
 printf("- Mealy machines often need fewer states\n");
 printf("- Mealy outputs can have glitches between clock edges\n");

 return 0;
}
